const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](
      JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: $json.sessionId || 'unknown', workflow: 'general-chat', message, meta })
    );
  }
};
const statusCode = $json.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';
jarvisLog('error', 'LLM request failed', { statusCode, statusMessage });
return [{ json: { ...$json, responseText: '⚠️ Could not generate a response. LLM returned error: ' + statusMessage, success: false } }];
